using Esolang.Generator;
using Esolang.Piet.Parser;
using Microsoft.CodeAnalysis;
using Microsoft.CodeAnalysis.CSharp;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using System.Collections.Immutable;
using System.Text;

namespace Esolang.Piet.Generator;

/// <summary>
/// A source generator that emits method implementations from <c>GeneratePietMethodAttribute</c>.
/// </summary>
[Generator(LanguageNames.CSharp)]
public partial class MethodGenerator : IIncrementalGenerator
{
    /// <summary>
    /// The standard auto-generated file header.
    /// </summary>
    public const string CommentAutoGenerated = "// <auto-generated/>";

    /// <summary>
    /// The namespace where the generated attribute is placed.
    /// </summary>
    public const string NameSpaceName = "Esolang.Piet";

    /// <summary>
    /// The generated attribute class name.
    /// </summary>
    public const string ClassNamePietAttribution = "GeneratePietMethodAttribute";

    /// <summary>
    /// The generated attribute class name for storing generation metadata.
    /// </summary>
    public const string GeneratedPietAttribution = "GeneratedPietInfoAttribute";

    /// <summary>
    /// The source file name used to aggregate generated methods.
    /// </summary>
    public const string GeneratedMethodsFileName = "GeneratePietMethod.g.cs";

    const string GeneratedMethodsFileHeader = $$"""
        {{CommentAutoGenerated}}
        #nullable enable
        #pragma warning disable CS0219
        #pragma warning disable CS1998

        """;

    readonly struct EmittedMethod(string source)
    {
        public string Source { get; } = source;
    }

    readonly struct AdditionalImageFile(string path, string? text, int? codelSize = null, string? transformedOriginalPath = null)
    {
        public string Path { get; } = path;

        public string? Text { get; } = text;

        public int? CodelSize { get; } = codelSize;

        public string? TransformedOriginalPath { get; } = transformedOriginalPath;

        public bool IsReadable => Text is not null;
        public static AdditionalImageFile Make(string path, string? text)
        {
            if (string.IsNullOrWhiteSpace(path) || text is null)
            {
                return new(path, text);
            }
            var codelSize = TryGetCodelSize(text, out var codelSize_) ? codelSize_ : (int?)null;
            var transformedOriginalPath = TryGetTransformedOriginalImagePath(text, out var transformedImagePath) ? transformedImagePath : null;
            var newText = string.Join("\n", text.Split('\n').Skip(2));
            return new(path, newText, codelSize, transformedOriginalPath);
        }
    }

    /// <summary>
    /// Initializes the generator and registers the attribute and method generation pipeline.
    /// </summary>
    /// <param name="context">The initialization context.</param>
    public void Initialize(IncrementalGeneratorInitializationContext context)
    {
        context.RegisterPostInitializationOutput(static context =>
            context.AddSource("GeneratePietMethodAttribute.cs", $$"""
                {{CommentAutoGenerated}}
                using System;
                using System.Diagnostics;
                namespace {{NameSpaceName}} {
                    [Conditional("COMPILE_TIME_ONLY")]
                    [AttributeUsage(AttributeTargets.Method, AllowMultiple = false, Inherited = false)]
                    internal sealed class {{ClassNamePietAttribution}} : Attribute
                    {
                        /// <summary>
                        /// Generate a Piet method implementation.
                        /// </summary>
                        /// <param name="imagePath">Path to the Piet image file.</param>
                        /// <param name="codelSize">Optional codel size for the Piet image.</param>
                        internal {{ClassNamePietAttribution}}(string imagePath, int codelSize = 0) { }
                    }

                    /// <summary>
                    /// An attribute to store information about the generated Piet method, used for testing and diagnostics.
                    /// </summary>
                    [Conditional("COMPILE_TIME_ONLY")]
                    [AttributeUsage(AttributeTargets.Method, AllowMultiple = false, Inherited = false)]
                    internal sealed class {{GeneratedPietAttribution}} : Attribute
                    {
                        /// <summary>
                        /// Creates a new instance of the <c>{{GeneratedPietAttribution}}</c> class.
                        /// </summary>
                        /// <param name="path">The path to the Piet image file used for generation.</param>
                        /// <param name="height">The height of the Piet image in codels.</param>
                        /// <param name="width">The width of the Piet image in codels.</param>
                        /// <param name="codelSize">The size of each codel in pixels.</param>
                        internal {{GeneratedPietAttribution}}(string path, int height, int width, int codelSize) { }
                    }
                }
                """));

        const string attributeNameSpaceName = NameSpaceName + "." + ClassNamePietAttribution;
        var source = context.SyntaxProvider.ForAttributeWithMetadataName(
            attributeNameSpaceName,
            static (node, token) => node is MethodDeclarationSyntax,
            static (context, token) => context
        );

        var generatedTargets = source.Collect();
        var additionalFiles = context.AdditionalTextsProvider
            .Select(static (additionalText, token) =>
            {
                var text = additionalText.GetText(token);
                return AdditionalImageFile.Make(additionalText.Path, text?.ToString());
            })
            .Collect();
        var languageVersion = context.ParseOptionsProvider
            .Select(static (parseOptions, token) =>
                parseOptions is CSharpParseOptions csharpParseOptions
                    ? csharpParseOptions.LanguageVersion
                    : LanguageVersion.Default);

        var projectDirrectory = context.AnalyzerConfigOptionsProvider
            .Select(static (provider, _) => provider.GlobalOptions.TryGetValue("build_property.MSBuildProjectDirectory", out var projectDirectory)
                || provider.GlobalOptions.TryGetValue("build_property.ProjectDir", out projectDirectory)
                ? projectDirectory : null);
        var compilation = context.CompilationProvider;
        var knownTypes = compilation.Select(static (c, _) => new KnownTypes(c));

        var generationInputs = generatedTargets.Combine(additionalFiles).Combine(languageVersion).Combine(projectDirrectory).Combine(knownTypes);

        context.RegisterSourceOutput(generationInputs, static (context, input) =>
        {
            ((((var sources, var imagePaths), var currentLanguageVersion), var projectDir), var types) = input;

            if (sources.IsDefaultOrEmpty)
            {
                return;
            }

            var builder = new StringBuilder(GeneratedMethodsFileHeader);
            var emittedCount = 0;
            var features = GeneratorFeatures.None;


            foreach (var source in sources)
            {
                var (emitted, features_) = Emit(context, source, imagePaths, currentLanguageVersion, projectDir, types);
                features |= features_;
                if (!emitted.HasValue)
                {
                    continue;
                }

                builder.AppendLine(emitted.Value.Source);
                emittedCount++;
            }

            if (emittedCount > 0)
            {
                context.AddSource(GeneratedMethodsFileName, builder.ToString());
            }
            if (TryMakePietRuntimeSource(features, out var runtimeFileName, out var runtimeSource))
                context.AddSource(runtimeFileName, runtimeSource);
        });
    }

    static readonly int DefaultCodelSize = 1;

    static (EmittedMethod?, GeneratorFeatures) Emit(
        SourceProductionContext context,
        GeneratorAttributeSyntaxContext source,
        ImmutableArray<AdditionalImageFile> additionalImageFiles,
        LanguageVersion currentLanguageVersion,
        string? projectDirectory,
        KnownTypes types)
    {
        if (source.TargetSymbol is not IMethodSymbol methodSymbol || source.TargetNode is not MethodDeclarationSyntax methodSyntax)
        {
            return (null, GeneratorFeatures.None);
        }

        if (methodSymbol.ContainingType is null)
        {
            return (null, GeneratorFeatures.None);
        }

        if (!IsLanguageVersionAtLeastCSharp8(currentLanguageVersion))
        {
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.LanguageVersionTooLow,
                methodSyntax.Identifier.GetLocation(),
                methodSymbol.Name,
                currentLanguageVersion.ToString()));
        }

        var ns = methodSymbol.ContainingNamespace?.IsGlobalNamespace == false
            ? methodSymbol.ContainingNamespace.ToDisplayString()
            : null;

        var typeKeyword = methodSymbol.ContainingType.TypeKind switch
        {
            TypeKind.Struct when methodSymbol.ContainingType.IsRecord => "record struct",
            TypeKind.Struct => "struct",
            TypeKind.Interface => "interface",
            TypeKind.Class when methodSymbol.ContainingType.IsRecord => "record",
            _ => "class",
        };

        if (source.Attributes[0].ConstructorArguments.FirstOrDefault().Value is not string imagePath || string.IsNullOrWhiteSpace(imagePath))
        {
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.InvalidImagePathParameter,
                methodSyntax.Identifier.GetLocation(),
                methodSymbol.Name));
            return EmitErrorMethod(
                methodSymbol,
                methodSyntax,
                ns,
                typeKeyword,
                null,
                projectDirectory,
                null,
                null,
                DiagnosticDescriptors.InvalidImagePathParameter.Id,
                "Invalid image path parameter"
            );
        }

        if (!methodSymbol.IsPartialDefinition)
        {
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.MethodMustBePartial,
                methodSyntax.Identifier.GetLocation(),
                methodSymbol.Name));
            return EmitErrorMethod(
                methodSymbol,
                methodSyntax,
                ns,
                typeKeyword,
                null,
                projectDirectory,
                null,
                null,
                DiagnosticDescriptors.MethodMustBePartial.Id,
                $"Method {methodSymbol.Name} must be declared as partial"
            );
        }

        if (TryResolveImagePath(imagePath, additionalImageFiles) is not { } resolvedImageFile)
        {
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.ImageFileNotFound,
                methodSyntax.Identifier.GetLocation(),
                imagePath));
            return EmitErrorMethod(
                methodSymbol,
                methodSyntax,
                ns,
                typeKeyword,
                null,
                projectDirectory,
                null,
                null,
                DiagnosticDescriptors.ImageFileNotFound.Id,
                $"Image file {imagePath} not found"
            );
        }

        // 属性でCodelSize指定があればそれを優先、なければ追加ファイルのPIET_CODEL_SIZEコメントを使う
        var codelSize = resolvedImageFile.CodelSize ?? DefaultCodelSize;
        // 属性引数（2つ目以降）にcodelSizeがあれば上書き
        if (source.Attributes[0].ConstructorArguments.Length > 1)
        {
            var arg = source.Attributes[0].ConstructorArguments[1];
            if (arg.Value is int attrCodelSize && attrCodelSize > 0)
            {
                codelSize = attrCodelSize;
            }
        }

        if (methodSymbol.TypeParameters.Length > 0)
        {
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.InvalidParameter,
                methodSyntax.Identifier.GetLocation(),
                methodSymbol.Name));
            return EmitErrorMethod(
                methodSymbol,
                methodSyntax,
                ns,
                typeKeyword,
                resolvedImageFile,
                projectDirectory,
                codelSize,
                null,
                DiagnosticDescriptors.InvalidParameter.Id,
                "Invalid parameter"
            );
        }

        var binding = MethodSignatureBinder.Bind(methodSymbol, types,
            invalidReturnTypeErrorId: DiagnosticDescriptors.InvalidReturnType.Id,
            invalidParameterErrorId: DiagnosticDescriptors.InvalidParameter.Id,
            duplicateParameterErrorId: DiagnosticDescriptors.DuplicateParameter.Id,
            returnOutputConflictErrorId: DiagnosticDescriptors.ReturnOutputConflict.Id);

        if (binding is { IsValid: true, UnhandledParameters.Count: > 0 })
        {
            foreach (var parameter in binding.UnhandledParameters)
            {
                var discriptor = DiagnosticDescriptors.InvalidParameter;
                var typeDisplayString = parameter.Type.ToDisplayString();
                context.ReportDiagnostic(Diagnostic.Create(discriptor, parameter.Locations[0], typeDisplayString));
                return EmitErrorMethod(
                    methodSymbol,
                    methodSyntax,
                    ns,
                    typeKeyword,
                    resolvedImageFile,
                    projectDirectory,
                    codelSize,
                    null,
                    DiagnosticDescriptors.InvalidParameter.Id,
                    string.Format(DiagnosticDescriptors.InvalidParameter.MessageFormat.ToString(), typeDisplayString)
                );
            }
        }

        if (!binding.IsValid)
        {
            if (string.Equals(binding.ErrorId, DiagnosticDescriptors.InvalidReturnType.Id, StringComparison.Ordinal))
            {
                context.ReportDiagnostic(Diagnostic.Create(
                    DiagnosticDescriptors.InvalidReturnType,
                    binding.Location ?? methodSyntax.Identifier.GetLocation(),
                    methodSymbol.ReturnType.ToDisplayString()));
                return EmitErrorMethod(
                    methodSymbol,
                    methodSyntax,
                    ns,
                    typeKeyword,
                    resolvedImageFile,
                    projectDirectory,
                    codelSize,
                    null,
                    DiagnosticDescriptors.InvalidReturnType.Id,
                    $"Invalid return type {methodSymbol.ReturnType.ToDisplayString()}"
                );
            }

            if (string.Equals(binding.ErrorId, DiagnosticDescriptors.DuplicateParameter.Id, StringComparison.Ordinal))
            {
                context.ReportDiagnostic(Diagnostic.Create(
                    DiagnosticDescriptors.DuplicateParameter,
                    binding.Location ?? methodSyntax.Identifier.GetLocation(),
                    methodSymbol.Name));
                return EmitErrorMethod(
                    methodSymbol,
                    methodSyntax,
                    ns,
                    typeKeyword,
                    resolvedImageFile,
                    projectDirectory,
                    codelSize,
                    null,
                    DiagnosticDescriptors.DuplicateParameter.Id,
                    $"Duplicate parameter types in method {methodSymbol.Name}"
                );
            }

            if (string.Equals(binding.ErrorId, DiagnosticDescriptors.ReturnOutputConflict.Id, StringComparison.Ordinal))
            {
                context.ReportDiagnostic(Diagnostic.Create(
                    DiagnosticDescriptors.ReturnOutputConflict,
                    binding.Location ?? methodSyntax.Identifier.GetLocation(),
                    methodSymbol.Name));
                return EmitErrorMethod(
                    methodSymbol,
                    methodSyntax,
                    ns,
                    typeKeyword,
                    resolvedImageFile,
                    projectDirectory,
                    codelSize,
                    null,
                    DiagnosticDescriptors.ReturnOutputConflict.Id,
                    $"Return and output conflict in method {methodSymbol.Name}"
                );
            }

            var unhandled = binding.UnhandledParameters.FirstOrDefault() ?? methodSymbol.Parameters.FirstOrDefault();
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.InvalidParameter,
                binding.Location ?? unhandled?.Locations.FirstOrDefault() ?? methodSyntax.Identifier.GetLocation(),
                unhandled?.Name ?? methodSymbol.Name));

            return EmitErrorMethod(
                methodSymbol,
                methodSyntax,
                ns,
                typeKeyword,
                resolvedImageFile,
                projectDirectory,
                codelSize,
                null,
                DiagnosticDescriptors.InvalidParameter.Id,
                $"Invalid parameter in method {methodSymbol.Name}"
            );
        }

        // --- 画像デコード拡張 ---
        var extension = GetExtension(resolvedImageFile.TransformedOriginalPath ?? resolvedImageFile.Path);
        byte[]? codels = null;
        int imageWidth = 0, imageHeight = 0;
        var bytes = ExtractBytes(resolvedImageFile);
        if (bytes is null)
        {
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.InvalidImageFormat,
                methodSyntax.Identifier.GetLocation(),
                imagePath));
            return EmitErrorMethod(
                methodSymbol,
                methodSyntax,
                ns,
                typeKeyword,
                resolvedImageFile,
                projectDirectory,
                codelSize,
                null,
                DiagnosticDescriptors.InvalidImageFormat.Id,
                $"The image file {imagePath} has an unsupported format or is not readable"
            );
        }
        if (!PietParser.TryParse(bytes, extension, codelSize, out var program))
        {
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.InvalidImageFormat,
                methodSyntax.Identifier.GetLocation(),
                imagePath));
            return EmitErrorMethod(
                methodSymbol,
                methodSyntax,
                ns,
                typeKeyword,
                resolvedImageFile,
                projectDirectory,
                codelSize,
                program,
                DiagnosticDescriptors.InvalidImageFormat.Id,
                $"The image file {imagePath} has an unsupported format or is not readable"
            );
        }
        codels = [.. program.Codels.Select(b => (byte)b)];
        imageWidth = program.Width;
        imageHeight = program.Height;

        if (codels is null || imageWidth <= 0 || imageHeight <= 0)
        {
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.InvalidImageFormat,
                methodSyntax.Identifier.GetLocation(),
                imagePath));
            return EmitErrorMethod(
                methodSymbol,
                methodSyntax,
                ns,
                typeKeyword,
                resolvedImageFile,
                projectDirectory,
                codelSize,
                program,
                DiagnosticDescriptors.InvalidImageFormat.Id,
                $"The image file {imagePath} has an unsupported format or is not readable"
            );
        }

        var (mightUseOutput, mightUseInput) = ScanPietIoCommands(codels, imageWidth, imageHeight);
        if (mightUseOutput && !binding.HasExplicitOutput)
        {
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.RequiredOutputInterface,
                methodSyntax.Identifier.GetLocation()));
        }

        if (mightUseInput && !binding.HasExplicitInput)
        {
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.RequiredInputInterface,
                methodSyntax.Identifier.GetLocation()));
        }

        if (!mightUseInput && binding.HasExplicitInput)
        {
            context.ReportDiagnostic(Diagnostic.Create(
                DiagnosticDescriptors.UnusedInputInterface,
                methodSyntax.Identifier.GetLocation()));
        }

        var containingTypeName = methodSymbol.ContainingType.Name;
        var staticModifier = methodSymbol.IsStatic ? " static" : string.Empty;
        var asyncModifier = binding.IsAsync ? " async" : string.Empty;
        var accessibility = GetAccessibility(methodSymbol.DeclaredAccessibility);
        var parameterList = string.Join(", ", methodSymbol.Parameters.Select(p =>
        {
            if (binding.IsAsyncEnumerable
                && binding.CancellationTokenName is not null
                && string.Equals(p.Name, binding.CancellationTokenName, StringComparison.Ordinal))
            {
                return "[global::System.Runtime.CompilerServices.EnumeratorCancellation] " + FormatParameter(p);
            }
            return FormatParameter(p);
        }));

        var code = new StringBuilder();
        if (ns is not null)
        {
            code.Append("namespace ").Append(ns).AppendLine(" {");
            code.AppendLine();
        }

        code.Append("partial ").Append(typeKeyword).Append(' ').Append(containingTypeName).AppendLine();
        code.AppendLine("{");
        // 使用データを表す属性
        code.Append("    ");
        AddGeneratedPietInfo(resolvedImageFile, codelSize, program, projectDirectory, code);
        var returnType = methodSymbol.ReturnType.ToDisplayString(SymbolDisplayFormat.FullyQualifiedFormat);
        code.Append("    ").Append(accessibility).Append(staticModifier).Append(asyncModifier).Append(" partial ").Append(returnType).Append(' ')
            .Append(methodSymbol.Name).Append('(').Append(parameterList).AppendLine(")");

        code.AppendLine("    {");

        EmitBody(
            code,
            binding,
            $"new byte[] {{ {string.Join(", ", codels)} }}",
            imageWidth.ToString(),
            imageHeight.ToString(),
            mightUseOutput,
            mightUseInput
        );

        code.AppendLine("    }");
        code.AppendLine("}");
        if (ns is not null)
        {
            code.AppendLine("}");
        }

        var generatorFeatures = GetGeneratorFeatures(binding);
        if (binding.LoggerExpression is not null)
            generatorFeatures |= GeneratorFeatures.UseLogging;

        return (new EmittedMethod(code.ToString()), generatorFeatures);
    }

    static GeneratorFeatures GetGeneratorFeatures(MethodSignatureBinding binding)
    {
        if (binding.IsAsyncEnumerable) return GeneratorFeatures.AsyncEnumerable;
        if (binding.IsEnumerable) return GeneratorFeatures.Enumerable;
        if (binding.IsAsync) return GeneratorFeatures.Async;
        return GeneratorFeatures.Sync;
    }

    static void EmitBody(
            StringBuilder builder,
            MethodSignatureBinding binding,
            string codelArrayExpression,
            string widthExpression,
            string heightExpression,
            bool mightUseOutput,
            bool mightUseInput
        )
    {
        var ctName = binding.CancellationTokenName ?? "default(global::System.Threading.CancellationToken)";
        // `cancellationToken: {cName}`
        var ctParameter = $"cancellationToken: {ctName}";
        var loggerExpr = binding.LoggerExpression ?? "null";
        // `logger: {loggerExpr}` or string.Empty
        var logParameter = binding.LoggerExpression is not null ? $"logger: {loggerExpr}," : string.Empty;

        var features = GetGeneratorFeatures(binding);

        // ------------------------------------------------------------
        // 入力デリゲート生成
        // ------------------------------------------------------------

        switch (binding)
        {
            case { InputKind: MethodInputKind.None } when features is GeneratorFeatures.Sync or GeneratorFeatures.Enumerable && mightUseInput:
                builder.AppendLine("""
                int? __pietReadNumber()
                    => throw new global::System.InvalidOperationException("PT0008: Required input interface not provided");
                int? __pietReadChar()
                    => throw new global::System.InvalidOperationException("PT0008: Required input interface not provided");
        """);
                break;
            case { InputKind: MethodInputKind.None } when features is GeneratorFeatures.Sync or GeneratorFeatures.Enumerable:
                builder.AppendLine("""
                int? __pietReadNumber() => (int?)null;
                int? __pietReadChar() => (int?)null;
        """);
                break;
            case { InputKind: MethodInputKind.None } when features is GeneratorFeatures.Async or GeneratorFeatures.AsyncEnumerable && mightUseInput:
                builder.AppendLine("""
                global::System.Threading.Tasks.ValueTask<int?> __pietReadNumberAsync(global::System.Threading.CancellationToken __ct)
                    => throw new global::System.InvalidOperationException("PT0008: Required input interface not provided");

                global::System.Threading.Tasks.ValueTask<int?> __pietReadCharAsync(global::System.Threading.CancellationToken __ct)
                    => throw new global::System.InvalidOperationException("PT0008: Required input interface not provided");
        """);
                break;
            case { InputKind: MethodInputKind.None } when features is GeneratorFeatures.Async or GeneratorFeatures.AsyncEnumerable:
                builder.AppendLine("""
                global::System.Threading.Tasks.ValueTask<int?> __pietReadNumberAsync(global::System.Threading.CancellationToken __ct)
                    => new global::System.Threading.Tasks.ValueTask<int?>((int?)null);

                global::System.Threading.Tasks.ValueTask<int?> __pietReadCharAsync(global::System.Threading.CancellationToken __ct)
                    => new global::System.Threading.Tasks.ValueTask<int?>((int?)null);
        """);
                break;
            case { InputKind: MethodInputKind.String } when features is GeneratorFeatures.Sync or GeneratorFeatures.Enumerable:
                builder.AppendLine($$"""
                var __pietStringReader = new global::System.IO.StringReader({{binding.InputExpression}});

                int? __pietReadNumber()
                {
                    var __line = __pietStringReader.ReadLine();
                    if (__line is null) return null;
                    return int.TryParse(__line, out var __n) ? __n : (int?)null;
                }

                int? __pietReadChar()
                {
                    var __ch = __pietStringReader.Read();
                    return __ch < 0 ? (int?)null : __ch;
                }
        """);
                break;

            case { InputKind: MethodInputKind.String } when features is GeneratorFeatures.Async or GeneratorFeatures.AsyncEnumerable:
                builder.AppendLine($$"""
                var __pietStringReader = new global::System.IO.StringReader({{binding.InputExpression}});

                global::System.Threading.Tasks.ValueTask<int?> __pietReadNumberAsync(global::System.Threading.CancellationToken __ct)
                {
                    var __line = __pietStringReader.ReadLine();
                    if (__line is null) return new((int?)null);
                    return new(int.TryParse(__line, out var __n) ? __n : (int?)null);
                }

                global::System.Threading.Tasks.ValueTask<int?> __pietReadCharAsync(global::System.Threading.CancellationToken __ct)
                {
                    var __ch = __pietStringReader.Read();
                    return new(__ch < 0 ? (int?)null : __ch);
                }
        """);
                break;

            case { InputKind: MethodInputKind.TextReader } when features is GeneratorFeatures.Sync or GeneratorFeatures.Enumerable:
                builder.AppendLine($$"""
                int? __pietReadNumber()
                {
                    var __line = {{binding.InputExpression}}.ReadLine();
                    if (__line is null) return null;
                    return int.TryParse(__line, out var __n) ? __n : (int?)null;
                }

                int? __pietReadChar()
                {
                    var __ch = {{binding.InputExpression}}.Read();
                    return __ch < 0 ? (int?)null : __ch;
                }
        """);
                break;

            case { InputKind: MethodInputKind.TextReader } when features is GeneratorFeatures.Async or GeneratorFeatures.AsyncEnumerable:
                builder.AppendLine($$"""
                global::System.Threading.Tasks.ValueTask<int?> __pietReadNumberAsync(global::System.Threading.CancellationToken __ct)
                {
            #if NET7_0_OR_GREATER
                    var __lineTask = {{binding.InputExpression}}.ReadLineAsync(__ct);
                    if (__lineTask.IsCompletedSuccessfully)
                    {
                        var __line = __lineTask.Result;
                        if (__line is null) return new((int?)null);
                        return new(int.TryParse(__line, out var __n) ? __n : (int?)null);
                    }
                    return __pietReadNumberAsyncAwaited(__ct);

                    async global::System.Threading.Tasks.ValueTask<int?> __pietReadNumberAsyncAwaited(global::System.Threading.CancellationToken ___ct)
                    {
                        var __line = await {{binding.InputExpression}}.ReadLineAsync(___ct).ConfigureAwait(false);
                        if (__line is null) return null;
                        return int.TryParse(__line, out var __n) ? __n : (int?)null;
                    }
            #else
                    return __pietReadNumberAsyncAwaited();

                    async global::System.Threading.Tasks.ValueTask<int?> __pietReadNumberAsyncAwaited()
                    {
                        var __line = await {{binding.InputExpression}}.ReadLineAsync().ConfigureAwait(false);
                        if (__line is null) return null;
                        return int.TryParse(__line, out var __n) ? __n : (int?)null;
                    }
            #endif
                }

                global::System.Threading.Tasks.ValueTask<int?> __pietReadCharAsync(global::System.Threading.CancellationToken __ct)
                {
                    var __ch = {{binding.InputExpression}}.Read();
                    return new(__ch < 0 ? (int?)null : __ch);
                }
        """);
                break;

            case { InputKind: MethodInputKind.PipeReader } when features is GeneratorFeatures.Sync or GeneratorFeatures.Enumerable:
                builder.AppendLine($$"""
                int? __pietReadNumber()
                {
                    var __result = {{binding.InputExpression}}.ReadAsync({{ctName}}).AsTask().GetAwaiter().GetResult();
                    var __buffer = __result.Buffer;
                    if (__buffer.IsEmpty)
                    {
                        {{binding.InputExpression}}.AdvanceTo(__buffer.End);
                        return null;
                    }

                    var __text = System.Text.Encoding.UTF8.GetString(global::System.Buffers.BuffersExtensions.ToArray(__buffer));
                    {{binding.InputExpression}}.AdvanceTo(__buffer.End);

                    __text = __text.Trim();
                    return int.TryParse(__text, out var __n) ? __n : (int?)null;
                }

                int? __pietReadChar()
                {
                    var __result = {{binding.InputExpression}}.ReadAsync({{ctName}}).AsTask().GetAwaiter().GetResult();
                    var __buffer = __result.Buffer;
                    if (__buffer.IsEmpty)
                    {
                        {{binding.InputExpression}}.AdvanceTo(__buffer.End);
                        return null;
                    }

                    var __first = 
            #if NET5_0_OR_GREATER
                        __buffer.FirstSpan[0];
            #else
                        __buffer.First.Span[0];
            #endif
                    var __pos = __buffer.GetPosition(1);
                    {{binding.InputExpression}}.AdvanceTo(__pos);
                    return __first;
                }
        """);
                break;

            case { InputKind: MethodInputKind.PipeReader } when features is GeneratorFeatures.Async or GeneratorFeatures.AsyncEnumerable:
                builder.AppendLine($$"""
                async global::System.Threading.Tasks.ValueTask<int?> __pietReadNumberAsync(global::System.Threading.CancellationToken __ct)
                {
                    var __result = await {{binding.InputExpression}}.ReadAsync(__ct).ConfigureAwait(false);
                    var __buffer = __result.Buffer;
                    if (__buffer.IsEmpty)
                    {
                        {{binding.InputExpression}}.AdvanceTo(__buffer.End);
                        return null;
                    }

                    var __text = global::System.Text.Encoding.UTF8.GetString(global::System.Buffers.BuffersExtensions.ToArray(__buffer));
                    {{binding.InputExpression}}.AdvanceTo(__buffer.End);

                    __text = __text.Trim();
                    return int.TryParse(__text, out var __n) ? __n : (int?)null;
                }

                async global::System.Threading.Tasks.ValueTask<int?> __pietReadCharAsync(global::System.Threading.CancellationToken __ct)
                {
                    var __result = await {{binding.InputExpression}}.ReadAsync(__ct).ConfigureAwait(false);
                    var __buffer = __result.Buffer;
                    if (__buffer.IsEmpty)
                    {
                        {{binding.InputExpression}}.AdvanceTo(__buffer.End);
                        return null;
                    }

                    var __first = 
            #if NET5_0_OR_GREATER
                        __buffer.FirstSpan[0];
            #else
                        __buffer.First.Span[0];
            #endif
                    var __pos = __buffer.GetPosition(1);
                    {{binding.InputExpression}}.AdvanceTo(__pos);
                    return __first;
                }
        """);
                break;
        }

        switch (binding)
        {
            case { OutputKind: MethodOutputKind.ReturnString } when features is GeneratorFeatures.Async or GeneratorFeatures.Sync:
                builder.AppendLine("""
                var __pietBytes = new global::System.Collections.Generic.List<byte>();
                void __pietWriteByte(byte b) => __pietBytes.Add(b);
        """);
                break;
            case { OutputKind: MethodOutputKind.TextWriter } when features is GeneratorFeatures.Async or GeneratorFeatures.Sync:
                builder.AppendLine($$"""
                void __pietWriteByte(byte b) => {{binding.OutputExpression}}.Write((char)b);
        """);
                break;
            case { OutputKind: MethodOutputKind.PipeWriter } when features is GeneratorFeatures.Async or GeneratorFeatures.Sync:
                builder.AppendLine($$"""
                void __pietWriteByte(byte b) => global::System.Buffers.BuffersExtensions.Write({{binding.OutputExpression}}, stackalloc byte[] { b });
        """);
                break;
            case { HasExplicitOutput: false } when features is GeneratorFeatures.Async or GeneratorFeatures.Sync && mightUseOutput:
                builder.AppendLine("""
                void __pietWriteByte(byte b) => throw new global::System.InvalidOperationException("PT0007: Required output interface not provided");
        """);
                break;
            case { } when features is GeneratorFeatures.Async or GeneratorFeatures.Sync:
                builder.AppendLine("""
                void __pietWriteByte(byte b) { }
        """);
                break;
