                        __pietWriteByte,
                        {{logParameter}}
                        {{ctParameter}}
                    );
                    return 0;
                }
        """);
                    break;
                }
            case MethodReturnKind.Void:
                {
                    builder.AppendLine($$"""
                {
                    global::Esolang.Piet.__Generated.PietRuntime.Execute(
                        {{codelArrayExpression}},
                        {{widthExpression}},
                        {{heightExpression}},
                        __pietReadNumber,
                        __pietReadChar,
                        __pietWriteByte,
                        {{logParameter}}
                        index: 0,
                        {{ctParameter}}
