        """);
                    break;
                }
            case MethodReturnKind.Task:
                {
                    builder.AppendLine($$"""
                {
                    await global::Esolang.Piet.__Generated.PietRuntime.ExecuteAsync(
                        {{codelArrayExpression}},
                        {{widthExpression}},
                        {{heightExpression}},
                        __pietReadNumberAsync,
                        __pietReadCharAsync,
                        __pietWriteByte,
                        {{logParameter}}
                        {{ctParameter}}
                    ).ConfigureAwait(false);
                }
        """);
                    break;
                }
            case MethodReturnKind.TaskInt32:
                {
                    builder.AppendLine($$"""
                {
                    await global::Esolang.Piet.__Generated.PietRuntime.ExecuteAsync(
                        {{codelArrayExpression}},
                        {{widthExpression}},
                        {{heightExpression}},
                        __pietReadNumberAsync,
                        __pietReadCharAsync,
                        __pietWriteByte,
                        {{logParameter}}
                        {{ctParameter}}
                    ).ConfigureAwait(false);
                    return 0;
                }
        """);
                    break;
                }
            case MethodReturnKind.ValueTask:
                {
                    builder.AppendLine($$"""
                {
                    await global::Esolang.Piet.__Generated.PietRuntime.ExecuteAsync(
                        {{codelArrayExpression}},
                        {{widthExpression}},
                        {{heightExpression}},
                        __pietReadNumberAsync,
                        __pietReadCharAsync,
                        __pietWriteByte,
                        {{logParameter}}
                        {{ctParameter}}
                    ).ConfigureAwait(false);
                }
        """);
                    break;
                }
            case MethodReturnKind.ValueTaskInt32:
                {
                    builder.AppendLine($$"""
                {
                    await global::Esolang.Piet.__Generated.PietRuntime.ExecuteAsync(
                        {{codelArrayExpression}},
                        {{widthExpression}},
                        {{heightExpression}},
                        __pietReadNumberAsync,
                        __pietReadCharAsync,
                        __pietWriteByte,
                        {{logParameter}}
                        {{ctParameter}}
                    ).ConfigureAwait(false);
                    return 0;
                }
        """);
                    break;
                }

            case MethodReturnKind.String or MethodReturnKind.NullableString:
                {
                    builder.AppendLine($$"""
                {
                    global::Esolang.Piet.__Generated.PietRuntime.Execute(
                        {{codelArrayExpression}},
                        {{widthExpression}},
                        {{heightExpression}},
                        __pietReadNumber,
                        __pietReadChar,
                        __pietWriteByte,
                        {{logParameter}}
                        {{ctParameter}}
                    );
                    var __pietString = global::System.Text.Encoding.UTF8.GetString(
        #if NET5_0_OR_GREATER
                        global::System.Runtime.InteropServices.CollectionsMarshal.AsSpan(
        #else
                        global::System.Linq.Enumerable.ToArray(
        #endif
                            __pietBytes
                        )
                    );
                    return __pietString;
                }
        """);
                    break;
                }

            // 2. Async: Task<string> / ValueTask<string>
            case MethodReturnKind.TaskString or MethodReturnKind.TaskNullableString:
                {
                    builder.AppendLine($$"""
                {
                    await global::Esolang.Piet.__Generated.PietRuntime.ExecuteAsync(
                        {{codelArrayExpression}},
                        {{widthExpression}},
                        {{heightExpression}},
                        __pietReadNumberAsync,
                        __pietReadCharAsync,
                        __pietWriteByte,
                        {{logParameter}}
                        {{ctParameter}}
                    ).ConfigureAwait(false);


                    var __pietString = global::System.Text.Encoding.UTF8.GetString(
        #if NET5_0_OR_GREATER
                        global::System.Runtime.InteropServices.CollectionsMarshal.AsSpan(
        #else
                        global::System.Linq.Enumerable.ToArray(
        #endif
                            __pietBytes
                        )
                    );
                    return __pietString;
                }
        """);
                    break;
                }

            case MethodReturnKind.ValueTaskString or MethodReturnKind.ValueTaskNullableString:
                {
                    builder.AppendLine($$"""
                {
                    await global::Esolang.Piet.__Generated.PietRuntime.ExecuteAsync(
                        {{codelArrayExpression}},
                        {{widthExpression}},
                        {{heightExpression}},
                        __pietReadNumberAsync,
                        __pietReadCharAsync,
                        __pietWriteByte,
                        {{logParameter}}
                        {{ctParameter}}
                    ).ConfigureAwait(false);

                    var __pietString = global::System.Text.Encoding.UTF8.GetString(
        #if NET5_0_OR_GREATER
                            global::System.Runtime.InteropServices.CollectionsMarshal.AsSpan(
        #else
                            global::System.Linq.Enumerable.ToArray(
        #endif
                            __pietBytes
