                    break;
                }

            // 3. Enumerable<byte>
            case MethodReturnKind.IEnumerableByte:
                {
                    builder.AppendLine($$"""
                foreach (var __pietByte in global::Esolang.Piet.__Generated.PietRuntime.ExecuteEnumerable(
                    {{codelArrayExpression}},
                    {{widthExpression}},
                    {{heightExpression}},
                    __pietReadNumber,
                    __pietReadChar,
                    {{logParameter}}
                    {{ctParameter}}))
